def rearrange_bigger(n):
    s = list(str(n))
    if len(s) == 1:
        return False
    k = len(s) - 2
    while k >= 0 and s[k] >= s[k+1]:
        k -= 1
    if k == -1:
        return False
    l = k
    while l+1 < len(s) and s[l+1] <= s[l]:
        l += 1
    s[k], s[l] = s[l], s[k]
    s[k+1:] = s[k+1:][::-1]
    return int(''.join(s))
